     1→import { auth, currentUser } from "@clerk/nextjs/server";
     2→import { NextResponse } from "next/server";
     3→import { prisma } from "@compass/db";
     4→
     5→export class AuthError extends Error {
     6→  constructor(
     7→    message: string,
     8→    public readonly status: 401 | 403 = 401
     9→  ) {
    10→    super(message);
    11→    this.name = "AuthError";
    12→  }
    13→}
    14→
    15→export function apiError(error: unknown): NextResponse {
    16→  if (error instanceof AuthError) {
    17→    return NextResponse.json({ error: error.message }, { status: error.status });
    18→  }
    19→  console.error("[API Error]", error);
    20→  return NextResponse.json({ error: "Internal server error" }, { status: 500 });
    21→}
    22→
    23→export async function requireStudent() {
    24→  const { userId } = await auth();
    25→  if (!userId) {
    26→    throw new AuthError("Unauthorized", 401);
    27→  }
    28→
    29→  const student = await prisma.student.findUnique({
    30→    where: { clerkId: userId },
    31→    include: {
    32→      school: true,
    33→      privacySettings: true,
    34→      notificationPrefs: true,
    35→    },
    36→  });
    37→
    38→  if (!student) {
    39→    throw new AuthError("Unauthorized", 401);
    40→  }
    41→
    42→  return student;
    43→}
    44→
    45→export async function requireCounselor() {
    46→  const { userId } = await auth();
    47→  if (!userId) {
    48→    throw new AuthError("Unauthorized", 401);
    49→  }
    50→
    51→  const counselor = await prisma.counselor.findUnique({
    52→    where: { clerkId: userId },
    53→    include: {
    54→      school: true,
    55→    },
    56→  });
    57→
    58→  if (!counselor) {
    59→    throw new AuthError("Forbidden", 403);
    60→  }
    61→
    62→  return counselor;
    63→}
    64→
    65→export async function getStudentOrNull() {
    66→  try {
    67→    return await requireStudent();
    68→  } catch {
    69→    return null;
    70→  }
    71→}
    72→
    73→export async function getCurrentUserId(): Promise<string | null> {
    74→  const { userId } = await auth();
    75→  return userId;
    76→}
    77→
    78→export async function requireAdmin() {
    79→  const user = await currentUser();
    80→  if (!user) throw new AuthError("Unauthorized", 401);
    81→  const role = user.publicMetadata?.role as string | undefined;
    82→  if (role !== "admin") throw new AuthError("Forbidden", 403);
    83→  return user;
    84→}
