     1→export function getISOWeekKey(date: Date): string {
     2→  // Use UTC getters throughout to avoid local-timezone skew on servers
     3→  const d = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
     4→  const dayOfWeek = d.getUTCDay() || 7;
     5→  d.setUTCDate(d.getUTCDate() + 4 - dayOfWeek);
     6→  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
     7→  const weekNum = Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
     8→  return `${d.getUTCFullYear()}-W${String(weekNum).padStart(2, "0")}`;
     9→}
