     1→import { NextResponse } from "next/server";
     2→import { requireStudent, apiError } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→import { rateLimiters } from "@/lib/redis";
     5→import { COOLDOWN_DAYS } from "@/lib/constants";
     6→
     7→export async function POST() {
     8→  try {
     9→    const student = await requireStudent();
    10→
    11→    const { success } = await rateLimiters.sessionCreate.limit(student.id);
    12→    if (!success) {
    13→      return NextResponse.json({ error: "Too many requests" }, { status: 429 });
    14→    }
    15→
    16→    const now = new Date();
    17→
    18→    // Check for existing in-progress session
    19→    const inProgress = await prisma.reflectionSession.findFirst({
    20→      where: { studentId: student.id, completedAt: null },
    21→      orderBy: { createdAt: "desc" },
    22→    });
    23→    if (inProgress) {
    24→      return NextResponse.json(inProgress);
    25→    }
    26→
    27→    // Enforce 3-week cooldown from last completed session
    28→    const lastCompleted = await prisma.reflectionSession.findFirst({
    29→      where: { studentId: student.id, completedAt: { not: null } },
    30→      orderBy: { completedAt: "desc" },
    31→    });
    32→
    33→    if (lastCompleted?.completedAt) {
    34→      const unlockDate = new Date(lastCompleted.completedAt);
    35→      unlockDate.setDate(unlockDate.getDate() + COOLDOWN_DAYS);
    36→      if (unlockDate > now) {
    37→        const daysLeft = Math.ceil((unlockDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
    38→        return NextResponse.json(
    39→          { error: "cooldown", daysLeft },
    40→          { status: 403 }
    41→        );
    42→      }
    43→    }
    44→
    45→    // Find next available template for current year
    46→    const currentYear = String(now.getFullYear());
    47→    const startedTemplateIds = (
    48→      await prisma.reflectionSession.findMany({
    49→        where: { studentId: student.id, templateId: { not: null } },
    50→        select: { templateId: true },
    51→      })
    52→    ).map((s) => s.templateId!);
    53→
    54→    const nextTemplate = await prisma.reflectionTemplate.findFirst({
    55→      where: {
    56→        yearKey: currentYear,
    57→        isActive: true,
    58→        id: { notIn: startedTemplateIds },
    59→      },
    60→      orderBy: { orderNum: "asc" },
    61→    });
    62→
    63→    if (!nextTemplate) {
    64→      return NextResponse.json(
    65→        { error: "all_complete" },
    66→        { status: 403 }
    67→      );
    68→    }
    69→
    70→    // Count sessions to assign session number
    71→    const sessionCount = await prisma.reflectionSession.count({
    72→      where: { studentId: student.id },
    73→    });
    74→
    75→    const session = await prisma.reflectionSession.create({
    76→      data: {
    77→        studentId: student.id,
    78→        templateId: nextTemplate.id,
    79→        sessionNumber: sessionCount + 1,
    80→      },
    81→      include: {
    82→        activities: true,
    83→        reflections: true,
    84→        template: true,
    85→      },
    86→    });
    87→
    88→    return NextResponse.json(session);
    89→  } catch (error) {
    90→    return apiError(error);
    91→  }
    92→}
    93→
    94→export async function GET() {
    95→  try {
    96→    const student = await requireStudent();
    97→
    98→    const sessions = await prisma.reflectionSession.findMany({
    99→      where: { studentId: student.id },
   100→      orderBy: { createdAt: "desc" },
   101→      include: {
   102→        template: { select: { title: true, orderNum: true } },
   103→        activities: { select: { id: true, name: true } },
   104→        reflections: {
   105→          select: {
   106→            id: true,
   107→            promptType: true,
   108→            wordCount: true,
   109→            createdAt: true,
   110→            isSharedWithCounselor: true,
   111→          },
   112→        },
   113→      },
   114→    });
   115→
   116→    return NextResponse.json(sessions);
   117→  } catch (error) {
   118→    return apiError(error);
   119→  }
   120→}
