     9→
    10→function getQStash() {
    11→  return new Client({ token: process.env.QSTASH_TOKEN! });
    12→}
    13→
    14→export async function POST(
    15→  _req: Request,
    16→  { params }: { params: Promise<{ id: string }> }
    17→) {
    18→  try {
    19→    const student = await requireStudent();
    20→    const { id } = await params;
    21→
    22→    const { success } = await rateLimiters.sessionSubmit.limit(student.id);
    23→    if (!success) {
    24→      return NextResponse.json({ error: "Too many requests" }, { status: 429 });
    25→    }
    26→
    27→    const session = await prisma.reflectionSession.findFirst({
    28→      where: { id, studentId: student.id },
    29→    });
    30→
    31→    if (!session) {
    32→      return NextResponse.json({ error: "Not found" }, { status: 404 });
    33→    }
    34→
    35→    if (session.completedAt) {
    36→      return NextResponse.json({ error: "Session already submitted" }, { status: 400 });
    37→    }
    38→
    39→    // Mark session as complete
    40→    const now = new Date();
    41→    const durationSeconds = Math.floor(
    42→      (now.getTime() - session.createdAt.getTime()) / 1000
    43→    );
    44→
    45→    await prisma.reflectionSession.update({
    46→      where: { id },
    47→      data: { completedAt: now, durationSeconds },
    48→    });
    49→
    50→    // Run synthesis directly (primary path — no external service dependency)
    51→    try {
    52→      const [activities, reflections, previousProfile] = await Promise.all([
    53→        prisma.activity.findMany({
    54→          where: { studentId: student.id },
    55→          orderBy: { createdAt: "asc" },
    56→        }),
    57→        prisma.reflection.findMany({
    58→          where: { studentId: student.id },
    59→          orderBy: { createdAt: "asc" },
    60→        }),
    61→        prisma.signalProfile.findFirst({
    62→          where: { studentId: student.id },
    63→          orderBy: { createdAt: "desc" },
    64→        }),
    65→      ]);
    66→
    67→      const synthesis = await synthesizeProfile({
    68→        studentId: student.id,
    69→        sessionId: id,
    70→        activities: activities.map((a) => ({
    71→          ...a,
    72→          hoursPerWeek: a.hoursPerWeek ? Number(a.hoursPerWeek) : null,
    73→        })),
    74→        reflections,
    75→        previousProfile,
    76→      });
    77→
    78→      await prisma.signalProfile.upsert({
    79→        where: { studentId_sessionId: { studentId: student.id, sessionId: id } },
    80→        create: {
    81→          studentId: student.id,
    82→          sessionId: id,
    83→          interestClusters: synthesis.interestClusters,
    84→          characterSignals: synthesis.characterSignals,
    85→          trajectoryShifts: synthesis.trajectoryShifts,
    86→          gapDetection: synthesis.gapDetection,
    87→          breadthScore: synthesis.breadthScore,
    88→          compressedSummary: synthesis.compressedSummary,
    89→          lastSynthesizedAt: new Date(),
    90→        },
    91→        update: {
    92→          interestClusters: synthesis.interestClusters,
    93→          characterSignals: synthesis.characterSignals,
    94→          trajectoryShifts: synthesis.trajectoryShifts,
    95→          gapDetection: synthesis.gapDetection,
    96→          breadthScore: synthesis.breadthScore,
    97→          compressedSummary: synthesis.compressedSummary,
    98→          lastSynthesizedAt: new Date(),
    99→        },
   100→      });
   101→
   102→      await Promise.all([
   103→        redis.del(CACHE_KEYS.signalProfile(student.id)),
   104→        redis.del(CACHE_KEYS.personalizedMap(student.id)),
   105→      ]).catch(() => {});
   106→    } catch (e) {
   107→      console.error("Direct synthesis failed:", e);
   108→      // Enqueue QStash as fallback so synthesis retries asynchronously
   109→      if (process.env.QSTASH_TOKEN) {
   110→        try {
   111→          const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
   112→          await getQStash().publishJSON({
   113→            url: `${appUrl}/api/webhooks/qstash`,
   114→            body: {
   115→              type: "POST_SESSION_SYNTHESIS",
   116→              data: { studentId: student.id, sessionId: id },
   117→              triggeredAt: now.toISOString(),
   118→            },
   119→            delay: 10,
   120→          });
   121→        } catch (qe) {
   122→          console.error("QStash fallback also failed:", qe);
   123→        }
   124→      }
   125→    }
   126→
   127→    return NextResponse.json({ success: true, completedAt: now });
   128→  } catch (error) {
   129→    return apiError(error);
   130→  }
   131→}
