     1→import { NextResponse } from "next/server";
     2→import { requireStudent, apiError } from "@/lib/auth";
     3→import { prisma } from "@compass/db";
     4→import { redis, CACHE_KEYS, CACHE_TTL, rateLimiters } from "@/lib/redis";
     5→
     6→export async function GET() {
     7→  try {
     8→    const student = await requireStudent();
     9→
    10→    const { success } = await rateLimiters.personalizedMap.limit(student.id);
    11→    if (!success) {
    12→      return NextResponse.json({ error: "Too many requests" }, { status: 429 });
    13→    }
    14→
    15→    // Check cache
    16→    const cached = await redis.get(CACHE_KEYS.personalizedMap(student.id));
    17→    if (cached) {
    18→      return NextResponse.json(cached);
    19→    }
    20→
    21→    // Get signal profile for embedding-based search
    22→    const signalProfile = await prisma.signalProfile.findFirst({
    23→      where: { studentId: student.id },
    24→      orderBy: { createdAt: "desc" },
    25→    });
    26→
    27→    let nodes;
    28→    let personalizedNodeIds: string[] = [];
    29→
    30→    if (signalProfile?.compressedSummary) {
    31→      // Use pgvector similarity search
    32→      // Generate embedding via AI service, then query
    33→      try {
    34→        const aiServiceUrl = process.env.AI_SERVICE_URL;
    35→        const aiServiceKey = process.env.AI_SERVICE_SECRET_KEY;
    36→
    37→        const embeddingResponse = await fetch(
    38→          `${aiServiceUrl}/embed`,
    39→          {
    40→            method: "POST",
    41→            headers: {
    42→              "Content-Type": "application/json",
    43→              "X-Service-Key": aiServiceKey!,
    44→            },
    45→            body: JSON.stringify({ text: signalProfile.compressedSummary }),
    46→          }
    47→        );
    48→
    49→        if (embeddingResponse.ok) {
    50→          const embeddingData = await embeddingResponse.json() as { embedding: unknown };
    51→          const rawEmbedding = embeddingData.embedding;
    52→          if (
    53→            !Array.isArray(rawEmbedding) ||
    54→            rawEmbedding.length !== 1024 ||
    55→            !rawEmbedding.every((v): v is number => typeof v === "number" && isFinite(v))
    56→          ) {
    57→            throw new Error("Invalid embedding from AI service");
    58→          }
    59→          const embedding = rawEmbedding;
    60→          const embeddingStr = `[${embedding.join(",")}]`;
    61→
    62→          // pgvector similarity search (raw query needed for vector ops)
    63→          const similarNodes = await prisma.$queryRaw<
    64→            Array<{ id: string; similarity: number }>
    65→          >`
    66→            SELECT id, 1 - (embedding <-> ${embeddingStr}::vector) as similarity
    67→            FROM "MapNode"
    68→            WHERE embedding IS NOT NULL
    69→            ORDER BY embedding <-> ${embeddingStr}::vector
    70→            LIMIT 50
    71→          `;
    72→
    73→          personalizedNodeIds = similarNodes.map((n) => n.id);
    74→
    75→          nodes = await prisma.mapNode.findMany({
    76→            where: { id: { in: personalizedNodeIds } },
    77→            select: {
    78→              id: true,
    79→              type: true,
    80→              label: true,
    81→              description: true,
    82→              metadata: true,
    83→              parentId: true,
    84→              createdAt: true,
    85→              updatedAt: true,
    86→            },
    87→          });
    88→
    89→          // Inject similarity scores
    90→          const simMap = new Map(
    91→            similarNodes.map((n) => [n.id, n.similarity])
    92→          );
    93→          nodes = nodes.map((n) => ({
    94→            ...n,
    95→            similarity: simMap.get(n.id) ?? 0,
    96→            isPersonalized: true,
    97→          }));
    98→        }
    99→      } catch {
   100→        // Fall through to non-personalized
   101→      }
   102→    }
   103→
   104→    if (!nodes || nodes.length === 0) {
   105→      // Fallback: return all nodes without personalization
   106→      nodes = await prisma.mapNode.findMany({
   107→        select: {
   108→          id: true,
   109→          type: true,
   110→          label: true,
   111→          description: true,
   112→          metadata: true,
   113→          parentId: true,
   114→          createdAt: true,
   115→          updatedAt: true,
   116→        },
   117→        take: 100,
   118→        orderBy: { label: "asc" },
   119→      });
   120→    }
   121→
   122→    // Get edges for these nodes
   123→    const nodeIds = nodes.map((n) => n.id);
   124→    const edges = await prisma.mapEdge.findMany({
   125→      where: {
   126→        OR: [
   127→          { sourceId: { in: nodeIds } },
   128→          { targetId: { in: nodeIds } },
   129→        ],
   130→      },
   131→    });
   132→
   133→    const result = {
   134→      nodes,
   135→      edges: edges.map((e) => ({
   136→        id: e.id,
   137→        source: e.sourceId,
   138→        target: e.targetId,
   139→        weight: e.weight,
   140→        edgeType: e.edgeType,
   141→      })),
   142→      personalizedNodeIds,
   143→      studentBreadthScore: signalProfile?.breadthScore ?? 0,
   144→    };
   145→
   146→    // Cache for 1 hour
   147→    await redis.setex(
   148→      CACHE_KEYS.personalizedMap(student.id),
   149→      CACHE_TTL.personalizedMap,
   150→      result
   151→    );
   152→
   153→    return NextResponse.json(result);
   154→  } catch (error) {
   155→    return apiError(error);
   156→  }
   157→}
