     6→import { COOLDOWN_DAYS } from "@/lib/constants";
     7→
     8→export default async function ReflectPage() {
     9→  const student = await requireStudent();
    10→  const now = new Date();
    11→
    12→  // Resume in-progress session if any
    13→  const inProgress = await prisma.reflectionSession.findFirst({
    14→    where: { studentId: student.id, completedAt: null },
    15→    orderBy: { createdAt: "desc" },
    16→  });
    17→  if (inProgress) {
    18→    redirect(`/reflect/${inProgress.id}`);
    19→  }
    20→
    21→  // Get last completed session for cooldown check
    22→  const lastCompleted = await prisma.reflectionSession.findFirst({
    23→    where: { studentId: student.id, completedAt: { not: null } },
    24→    orderBy: { completedAt: "desc" },
    25→    include: { template: { select: { title: true, orderNum: true } } },
    26→  });
    27→
    28→  // Check cooldown
    29→  let daysLeft = 0;
    30→  if (lastCompleted?.completedAt) {
    31→    const unlockDate = new Date(lastCompleted.completedAt);
    32→    unlockDate.setDate(unlockDate.getDate() + COOLDOWN_DAYS);
    33→    daysLeft = Math.max(0, Math.ceil((unlockDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)));
    34→  }
    35→
    36→  // Find next available template
    37→  const currentYear = String(now.getFullYear());
    38→  const startedTemplateIds = (
    39→    await prisma.reflectionSession.findMany({
    40→      where: { studentId: student.id, templateId: { not: null } },
    41→      select: { templateId: true },
    42→    })
    43→  ).map((s) => s.templateId!);
    44→
    45→  const nextTemplate = await prisma.reflectionTemplate.findFirst({
    46→    where: { yearKey: currentYear, isActive: true, id: { notIn: startedTemplateIds } },
    47→    orderBy: { orderNum: "asc" },
    48→  });
    49→
    50→  const totalTemplates = await prisma.reflectionTemplate.count({
    51→    where: { yearKey: currentYear, isActive: true },
    52→  });
    53→
    54→  const completedCount = await prisma.reflectionSession.count({
    55→    where: { studentId: student.id, completedAt: { not: null } },
    56→  });
    57→
    58→  // All done for the year
    59→  if (!nextTemplate) {
    60→    return (
    61→      <div className="min-h-[60vh] flex items-center justify-center">
    62→        <div className="glass-card p-8 text-center max-w-sm">
    63→          <div className="text-5xl mb-4">🎉</div>
    64→          <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
    65→            All reflections complete for {currentYear}
    66→          </h2>
    67→          <p className="text-[#6B7280] text-sm mb-6">
    68→            You&apos;ve finished all {totalTemplates} reflections this year. Check back next year.
    69→          </p>
    70→          <Link href="/" className="btn-primary">Back to Home</Link>
    71→        </div>
    72→      </div>
    73→    );
    74→  }
    75→
    76→  // In cooldown
    77→  if (daysLeft > 0) {
    78→    return (
    79→      <div className="min-h-[60vh] flex items-center justify-center">
    80→        <div className="glass-card p-8 text-center max-w-sm">
    81→          <div className="w-16 h-16 rounded-full bg-blue-100 flex items-center justify-center text-2xl font-bold text-[#3B82F6] mx-auto mb-4">
    82→            {daysLeft}
    83→          </div>
    84→          <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
    85→            Next reflection opens in {daysLeft} day{daysLeft !== 1 ? "s" : ""}
    86→          </h2>
    87→          <p className="text-[#6B7280] text-sm mb-2">
    88→            Up next: <span className="font-medium text-[#1A1A2E]">Reflection {nextTemplate.orderNum}: {nextTemplate.title}</span>
    89→          </p>
    90→          <p className="text-xs text-[#9CA3AF] mb-6">
    91→            {completedCount} of {totalTemplates} reflections done this year
    92→          </p>
    93→          <Link href="/" className="btn-primary">Back to Home</Link>
    94→        </div>
    95→      </div>
    96→    );
    97→  }
    98→
    99→  // Ready to start next reflection
   100→  return (
   101→    <div className="min-h-[60vh] flex items-center justify-center">
   102→      <div className="glass-card p-8 text-center max-w-sm">
   103→        <div className="text-5xl mb-4">🧭</div>
   104→        <p className="text-xs text-[#9CA3AF] mb-1 uppercase tracking-wide font-medium">
   105→          Reflection {nextTemplate.orderNum} of {totalTemplates}
   106→        </p>
   107→        <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
   108→          {nextTemplate.title}
   109→        </h2>
   110→        {nextTemplate.description && (
   111→          <p className="text-[#6B7280] text-sm mb-6">{nextTemplate.description}</p>
   112→        )}
   113→        {!nextTemplate.description && (
   114→          <p className="text-[#6B7280] text-sm mb-6">
   115→            10–15 minutes to capture what&apos;s been on your mind.
   116→          </p>
   117→        )}
   118→        <StartSessionButton />
   119→      </div>
   120→    </div>
   121→  );
   122→}
