     1→"use client";
     2→
     3→import { useState, useEffect, useRef } from "react";
     4→import { Button } from "@compass/ui";
     5→
     6→interface Reflection {
     7→  id: string;
     8→  promptText: string;
     9→  responseText: string | null;
    10→  promptType: string;
    11→  isSharedWithCounselor: boolean;
    12→}
    13→
    14→interface Session {
    15→  id: string;
    16→  reflections: Reflection[];
    17→  activities: unknown[];
    18→}
    19→
    20→interface Prompt {
    21→  promptText: string;
    22→  promptType: string;
    23→}
    24→
    25→export default function ReflectionPromptsStep({
    26→  session,
    27→  onNext,
    28→  onBack,
    29→}: {
    30→  session: Session;
    31→  onNext: (reflections: Reflection[]) => void;
    32→  onBack: () => void;
    33→}) {
    34→  const [prompts, setPrompts] = useState<Prompt[]>([]);
    35→  const [responses, setResponses] = useState<Record<number, string>>({});
    36→  const [savedIds, setSavedIds] = useState<Record<number, string>>({});
    37→  const [loadingPrompts, setLoadingPrompts] = useState(true);
    38→  const [saving, setSaving] = useState(false);
    39→  const autoSaveTimers = useRef<Record<number, NodeJS.Timeout>>({});
    40→  const creatingRef = useRef<Set<number>>(new Set());
    41→
    42→  useEffect(() => {
    43→    async function fetchPrompts() {
    44→      try {
    45→        const res = await fetch("/api/sessions/prompts", {
    46→          method: "POST",
    47→          headers: { "Content-Type": "application/json" },
    48→          body: JSON.stringify({ sessionId: session.id }),
    49→        });
    50→
    51→        if (res.ok) {
    52→          const data = await res.json() as { prompts: (Prompt & { text?: string; type?: string })[] };
    53→          // Normalize template format {text, type} to {promptText, promptType}
    54→          setPrompts(
    55→            data.prompts.map((p) => ({
    56→              promptText: p.promptText ?? p.text ?? "",
    57→              promptType: p.promptType ?? p.type ?? "PATTERN",
    58→            }))
    59→          );
    60→        }
    61→      } catch {
    62→        // Fallback prompts
    63→        setPrompts([
    64→          {
    65→            promptText:
    66→              "What activity from this month felt most alive or energizing to you?",
    67→            promptType: "PATTERN",
    68→          },
    69→          {
    70→            promptText:
    71→              "What have you been curious about lately that you haven't had time to explore?",
    72→            promptType: "EXPLORATION",
    73→          },
    74→        ]);
    75→      } finally {
    76→        setLoadingPrompts(false);
    77→      }
    78→    }
    79→
    80→    fetchPrompts();
    81→  }, [session.id]);
    82→
    83→  function handleResponseChange(index: number, value: string) {
    84→    setResponses((prev) => ({ ...prev, [index]: value }));
    85→
    86→    // Auto-save with debounce
    87→    if (autoSaveTimers.current[index]) {
    88→      clearTimeout(autoSaveTimers.current[index]);
    89→    }
    90→    autoSaveTimers.current[index] = setTimeout(() => {
    91→      autoSave(index, value);
    92→    }, 3000);
    93→  }
    94→
    95→  async function autoSave(index: number, text: string) {
    96→    if (!prompts[index] || !text.trim()) return;
    97→
    98→    const prompt = prompts[index]!;
    99→
   100→    if (savedIds[index]) {
   101→      // Update existing reflection
   102→      await fetch(`/api/reflections/${savedIds[index]}`, {
   103→        method: "PATCH",
   104→        headers: { "Content-Type": "application/json" },
   105→        body: JSON.stringify({ responseText: text }),
   106→      });
   107→    } else {
   108→      // Guard against concurrent creates for the same prompt index
   109→      if (creatingRef.current.has(index)) return;
   110→      creatingRef.current.add(index);
   111→      try {
   112→        const res = await fetch("/api/reflections", {
   113→          method: "POST",
   114→          headers: { "Content-Type": "application/json" },
   115→          body: JSON.stringify({
   116→            sessionId: session.id,
   117→            promptText: prompt.promptText,
   118→            responseText: text,
   119→            promptType: prompt.promptType,
   120→            isSharedWithCounselor: false,
   121→          }),
   122→        });
   123→
   124→        if (res.ok) {
   125→          const reflection = await res.json() as { id: string };
   126→          setSavedIds((prev) => ({ ...prev, [index]: reflection.id }));
   127→        }
   128→      } finally {
   129→        creatingRef.current.delete(index);
   130→      }
   131→    }
   132→  }
   133→
   134→  async function handleNext() {
   135→    setSaving(true);
   136→    // Save any unsaved responses
   137→    for (let i = 0; i < prompts.length; i++) {
   138→      const response = responses[i];
   139→      if (response?.trim() && !savedIds[i]) {
   140→        await autoSave(i, response);
   141→      }
   142→    }
   143→
   144→    // Fetch updated reflections
