     8→const createReflectionSchema = z.object({
     9→  sessionId: z.string(),
    10→  promptText: z.string().min(1).max(2000),
    11→  responseText: z.string().max(10000).optional(),
    12→  promptType: z.nativeEnum(PromptType),
    13→  isSharedWithCounselor: z.boolean().default(false),
    14→});
