    18→    const student = await requireStudent();
    19→
    20→    const { success } = await rateLimiters.reflectionsCreate.limit(student.id);
    21→    if (!success) {
    22→      return NextResponse.json({ error: "Too many requests" }, { status: 429 });
    23→    }
    24→
    25→    const body = await req.json();
    26→    const data = createReflectionSchema.parse(body);
    27→
    28→    // Validate session belongs to student
    29→    const session = await prisma.reflectionSession.findFirst({
    30→      where: { id: data.sessionId, studentId: student.id },
    31→    });
    32→    if (!session) {
    33→      return NextResponse.json({ error: "Session not found" }, { status: 404 });
    34→    }
    35→
    36→    const wordCount = data.responseText
    37→      ? data.responseText.trim().split(/\s+/).filter(Boolean).length
    38→      : 0;
    39→
    40→    const reflection = await prisma.reflection.create({
    41→      data: {
    42→        studentId: student.id,
    43→        sessionId: data.sessionId,
    44→        promptText: data.promptText,
    45→        responseText: data.responseText,
    46→        promptType: data.promptType,
    47→        isSharedWithCounselor: data.isSharedWithCounselor,
    48→        wordCount,
    49→      },
    50→    });
    51→
    52→    return NextResponse.json(reflection, { status: 201 });
