     1→import { NextResponse } from "next/server";
     2→import { verifySignatureAppRouter } from "@upstash/qstash/nextjs";
     3→import { prisma } from "@compass/db";
     4→import { aiService } from "@/lib/ai-service";
     5→import { redis, CACHE_KEYS } from "@/lib/redis";
     6→import { getISOWeekKey } from "@/lib/utils";
     7→import { Client } from "@upstash/qstash";
     8→
     9→export const dynamic = "force-dynamic";
    10→export const maxDuration = 60;
    11→
    12→function getQStash() {
    13→  return new Client({ token: process.env.QSTASH_TOKEN! });
    14→}
    15→
    16→interface QStashPayload {
    17→  type: "WEEKLY_NUDGE_SWEEP" | "OPPORTUNITY_SWEEP" | "POST_SESSION_SYNTHESIS" | "EMBED_PROFILE";
    18→  data: Record<string, unknown>;
    19→  triggeredAt: string;
    20→}
    21→
    22→
    23→async function handler(req: Request) {
    24→  const body = (await req.json()) as QStashPayload;
    25→
    26→  switch (body.type) {
    27→    case "POST_SESSION_SYNTHESIS": {
    28→      const { studentId, sessionId } = body.data as {
    29→        studentId: string;
    30→        sessionId: string;
    31→      };
    32→      await handlePostSessionSynthesis(studentId, sessionId);
    33→      break;
    34→    }
    35→
    36→    case "WEEKLY_NUDGE_SWEEP": {
    37→      await handleWeeklyNudgeSweep();
    38→      break;
    39→    }
    40→
    41→    case "OPPORTUNITY_SWEEP": {
    42→      await handleOpportunitySweep();
    43→      break;
    44→    }
    45→
    46→    case "EMBED_PROFILE": {
    47→      const { studentId, summary } = body.data as {
    48→        studentId: string;
    49→        summary: string;
    50→      };
    51→      await handleEmbedProfile(studentId, summary);
    52→      break;
    53→    }
    54→
    55→    default:
    56→      return NextResponse.json(
    57→        { error: "Unknown job type" },
    58→        { status: 400 }
    59→      );
    60→  }
    61→
    62→  return NextResponse.json({ success: true });
    63→}
    64→
    65→async function handlePostSessionSynthesis(
    66→  studentId: string,
    67→  sessionId: string
    68→) {
    69→  // Fetch all relevant data
    70→  const [activities, reflections, previousProfile] = await Promise.all([
    71→    prisma.activity.findMany({
    72→      where: { studentId },
    73→      orderBy: { createdAt: "asc" },
    74→    }),
    75→    prisma.reflection.findMany({
    76→      where: { studentId },
    77→      orderBy: { createdAt: "asc" },
    78→    }),
    79→    prisma.signalProfile.findFirst({
    80→      where: { studentId },
    81→      orderBy: { createdAt: "desc" },
    82→    }),
    83→  ]);
    84→
    85→  const synthesis = await aiService.synthesizeProfile({
    86→    studentId,
    87→    sessionId,
    88→    activities,
    89→    reflections,
    90→    previousProfile,
    91→  });
    92→
    93→  // Save new signal profile (upsert for idempotency — QStash has at-least-once delivery)
    94→  await prisma.signalProfile.upsert({
    95→    where: { studentId_sessionId: { studentId, sessionId } },
    96→    create: {
    97→      studentId,
    98→      sessionId,
    99→      interestClusters: synthesis.interestClusters as object[],
   100→      characterSignals: synthesis.characterSignals as object[],
   101→      trajectoryShifts: synthesis.trajectoryShifts as object[],
   102→      gapDetection: synthesis.gapDetection as object,
   103→      breadthScore: synthesis.breadthScore,
   104→      compressedSummary: synthesis.compressedSummary,
   105→      lastSynthesizedAt: new Date(),
   106→    },
   107→    update: {
   108→      interestClusters: synthesis.interestClusters as object[],
   109→      characterSignals: synthesis.characterSignals as object[],
   110→      trajectoryShifts: synthesis.trajectoryShifts as object[],
   111→      gapDetection: synthesis.gapDetection as object,
   112→      breadthScore: synthesis.breadthScore,
   113→      compressedSummary: synthesis.compressedSummary,
   114→      lastSynthesizedAt: new Date(),
   115→    },
   116→  });
   117→
   118→  // Invalidate caches
   119→  await Promise.all([
   120→    redis.del(CACHE_KEYS.signalProfile(studentId)),
   121→    redis.del(CACHE_KEYS.personalizedMap(studentId)),
   122→  ]);
   123→
   124→  // Enqueue embedding update if AI service is available
   125→  try {
   126→    const aiServiceUrl = process.env.AI_SERVICE_URL;
   127→    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
   128→    if (aiServiceUrl) {
   129→      await getQStash().publishJSON({
   130→        url: `${appUrl}/api/webhooks/qstash`,
   131→        body: {
   132→          type: "EMBED_PROFILE",
   133→          data: { studentId, summary: synthesis.compressedSummary },
   134→          triggeredAt: new Date().toISOString(),
   135→        },
   136→        delay: 5,
   137→      });
   138→    }
   139→  } catch {
   140→    // Non-critical: embedding is for personalized map, not core feature
   141→  }
   142→}
   143→
   144→async function handleWeeklyNudgeSweep() {
   145→  const now = new Date();
   146→  const cutoff90Days = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
   147→  const cutoff48Hours = new Date(now.getTime() - 48 * 60 * 60 * 1000);
   148→  const cutoff72Hours = new Date(now.getTime() - 72 * 60 * 60 * 1000);
   149→
   150→  // Get all students with notification preferences enabled
   151→  const students = await prisma.student.findMany({
   152→    where: { onboardingCompleted: true },
   153→    include: {
   154→      notificationPrefs: true,
   155→      sessions: {
   156→        orderBy: { createdAt: "desc" },
   157→        take: 1,
   158→        select: { completedAt: true, createdAt: true },
   159→      },
   160→      notifications: {
   161→        where: {
   162→          type: "REFLECTION_NUDGE",
   163→          createdAt: { gte: cutoff48Hours },
   164→        },
   165→        take: 1,
   166→      },
   167→      signalProfiles: {
   168→        orderBy: { createdAt: "desc" },
   169→        take: 1,
   170→        select: { compressedSummary: true },
   171→      },
   172→    },
   173→  });
   174→
   175→  const weekKey = getISOWeekKey(now);
   176→
   177→  for (const student of students) {
   178→    const prefs = student.notificationPrefs;
   179→    if (!prefs?.reflectionNudges) continue;
   180→
   181→    // Check weekly cap
   182→    const weeklyCount = (await redis.get(
   183→      `notif-count:${student.id}:${weekKey}`
   184→    )) as number | null;
   185→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
   186→
   187→    // Check 48hr cooldown
   188→    if (student.notifications.length > 0) continue;
   189→
   190→    // Check 72hr post-session cooldown
   191→    const lastSession = student.sessions[0];
   192→    if (lastSession?.completedAt) {
   193→      const sessionCompletedAt = new Date(lastSession.completedAt);
   194→      if (sessionCompletedAt > cutoff72Hours) continue;
   195→
   196→      // Only nudge if it's been more than 35 days (approaching monthly)
   197→      const daysSinceSession = Math.floor(
   198→        (now.getTime() - sessionCompletedAt.getTime()) / (1000 * 60 * 60 * 24)
   199→      );
   200→      if (daysSinceSession < 25) continue;
   201→    }
   202→
   203→    // Check quiet hours
   204→    const hour = now.getHours();
   205→    const quietStart = parseInt(prefs.quietHoursStart?.split(":")[0] ?? "21");
   206→    const quietEnd = parseInt(prefs.quietHoursEnd?.split(":")[0] ?? "8");
   207→    const inQuietHours =
   208→      quietStart > quietEnd
   209→        ? hour >= quietStart || hour < quietEnd
   210→        : hour >= quietStart && hour < quietEnd;
   211→    if (inQuietHours) continue;
   212→
   213→    // Generate personalized notification
   214→    try {
   215→      const content = await aiService.generateNotification({
   216→        studentId: student.id,
   217→        triggerType: "REFLECTION_NUDGE",
   218→        compressedSummary:
   219→          student.signalProfiles[0]?.compressedSummary ?? undefined,
   220→      });
   221→
   222→      await prisma.notification.create({
   223→        data: {
   224→          studentId: student.id,
   225→          type: "REFLECTION_NUDGE",
   226→          title: content.title,
   227→          body: content.body,
   228→        },
   229→      });
   230→
   231→      // Increment weekly count
   232→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
   233→      await redis.expire(
   234→        `notif-count:${student.id}:${weekKey}`,
   235→        60 * 60 * 24 * 7
   236→      );
   237→    } catch {
   238→      // Log and continue
   239→      console.error(`Failed to generate nudge for student ${student.id}`);
   240→    }
   241→  }
   242→}
