   244→async function handleOpportunitySweep() {
   245→  // Find upcoming opportunities (programs with deadlines within 3 weeks)
   246→  const threeWeeksOut = new Date();
   247→  threeWeeksOut.setDate(threeWeeksOut.getDate() + 21);
   248→
   249→  // Get all students with signal profiles
   250→  const students = await prisma.student.findMany({
   251→    where: { onboardingCompleted: true },
   252→    include: {
   253→      signalProfiles: {
   254→        orderBy: { createdAt: "desc" },
   255→        take: 1,
   256→        select: { compressedSummary: true, interestClusters: true },
   257→      },
   258→      notificationPrefs: true,
   259→    },
   260→    take: 100,
   261→  });
   262→
   263→  // For each student with a profile, generate an opportunity notification
   264→  for (const student of students) {
   265→    const prefs = student.notificationPrefs;
   266→    if (!prefs?.opportunityAlerts) continue;
   267→
   268→    const profile = student.signalProfiles[0];
   269→    if (!profile?.compressedSummary) continue;
   270→
   271→    // Check weekly cap
   272→    const now = new Date();
   273→    const weekKey = getISOWeekKey(now);
   274→    const weeklyCount = (await redis.get(
   275→      `notif-count:${student.id}:${weekKey}`
   276→    )) as number | null;
   277→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
   278→
   279→    // Check for recent opportunity notification (7 days cooldown)
   280→    const recentOpportunity = await prisma.notification.findFirst({
   281→      where: {
   282→        studentId: student.id,
   283→        type: "OPPORTUNITY",
   284→        createdAt: {
   285→          gte: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000),
   286→        },
   287→      },
   288→    });
   289→    if (recentOpportunity) continue;
   290→
   291→    try {
   292→      const content = await aiService.generateNotification({
   293→        studentId: student.id,
   294→        triggerType: "OPPORTUNITY",
   295→        compressedSummary: profile.compressedSummary,
   296→      });
   297→
   298→      await prisma.notification.create({
   299→        data: {
   300→          studentId: student.id,
   301→          type: "OPPORTUNITY",
   302→          title: content.title,
   303→          body: content.body,
   304→        },
   305→      });
   306→
   307→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
   308→      await redis.expire(`notif-count:${student.id}:${weekKey}`, 60 * 60 * 24 * 7);
   309→    } catch {
   310→      console.error(`Failed opportunity sweep for student ${student.id}`);
   311→    }
   312→  }
   313→}
