   315→async function handleEmbedProfile(studentId: string, summary: string) {
   316→  const aiServiceUrl = process.env.AI_SERVICE_URL;
   317→  if (!aiServiceUrl) return;
   318→
   319→  const res = await fetch(`${aiServiceUrl}/embed`, {
   320→    method: "POST",
   321→    headers: { "Content-Type": "application/json" },
   322→    body: JSON.stringify({ text: summary }),
   323→  });
   324→
   325→  if (!res.ok) {
   326→    throw new Error(`AI embed service returned ${res.status}`);
   327→  }
   328→
   329→  const embeddingData = (await res.json()) as { embedding: unknown };
   330→  const rawEmbedding = embeddingData.embedding;
   331→
   332→  if (
   333→    !Array.isArray(rawEmbedding) ||
   334→    rawEmbedding.length !== 1024 ||
   335→    !rawEmbedding.every((v): v is number => typeof v === "number" && isFinite(v))
   336→  ) {
   337→    throw new Error("Invalid embedding from AI service");
   338→  }
   339→
   340→  await redis.set(
   341→    `student-embedding:${studentId}`,
   342→    JSON.stringify(rawEmbedding),
   343→    { ex: 60 * 60 * 24 * 7 }
   344→  );
   345→}
