   348→// (which throws when QSTASH signing keys are missing during Next.js build)
   349→let wrappedHandler: ReturnType<typeof verifySignatureAppRouter> | null = null;
   350→
   351→export async function POST(req: Request) {
   352→  if (!wrappedHandler) {
   353→    wrappedHandler = verifySignatureAppRouter(handler);
   354→  }
   355→  return wrappedHandler(req);
   356→}
