     3→import { COOLDOWN_DAYS } from "@/lib/constants";
     4→
     5→interface Session {
     6→  completedAt?: Date | string | null;
     7→}
     8→
     9→function getDaysUntilNext(lastSession: Session | null): number {
    10→  if (!lastSession?.completedAt) return 0;
    11→
    12→  const completedAt = new Date(lastSession.completedAt);
    13→  const unlockDate = new Date(completedAt);
    14→  unlockDate.setDate(unlockDate.getDate() + COOLDOWN_DAYS);
    15→
    16→  const now = new Date();
    17→  return Math.max(0, Math.ceil((unlockDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)));
    18→}
    19→
    20→export default function SessionCountdown({
    21→  lastSession,
    22→}: {
    23→  lastSession: Session | null;
    24→}) {
    25→  const daysUntil = getDaysUntilNext(lastSession);
    26→
    27→  if (!lastSession || daysUntil === 0) return null;
    28→
    29→  return (
    30→    <div className="glass-card p-4">
    31→      <div className="flex items-center gap-3">
    32→        <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-[#3B82F6] text-lg font-bold">
    33→          {daysUntil}
    34→        </div>
    35→        <div>
