   188→export default function TemplateManager({ templates: initial }: { templates: Template[] }) {
   189→  const router = useRouter();
   190→  const [templates, setTemplates] = useState(initial);
   191→  const [creating, setCreating] = useState(false);
   192→  const [editingId, setEditingId] = useState<string | null>(null);
   193→
   194→  const existingOrders = templates.map((t) => t.orderNum);
   195→
   196→  async function handleCreate(data: object) {
   197→    const res = await fetch("/api/admin/templates", {
   198→      method: "POST",
   199→      headers: { "Content-Type": "application/json" },
   200→      body: JSON.stringify(data),
   201→    });
   202→    if (!res.ok) {
   203→      const err = await res.json() as { error: string };
   204→      throw new Error(err.error);
   205→    }
   206→    setCreating(false);
   207→    router.refresh();
   208→  }
   209→
   210→  async function handleUpdate(id: string, data: object) {
   211→    const res = await fetch(`/api/admin/templates/${id}`, {
   212→      method: "PATCH",
   213→      headers: { "Content-Type": "application/json" },
   214→      body: JSON.stringify(data),
   215→    });
   216→    if (!res.ok) {
   217→      const err = await res.json() as { error: string };
   218→      throw new Error(err.error);
   219→    }
   220→    setEditingId(null);
   221→    router.refresh();
   222→  }
   223→
   224→  async function handleDelete(id: string) {
   225→    if (!confirm("Delete this template? Students who haven't started it will no longer see it.")) return;
   226→    const res = await fetch(`/api/admin/templates/${id}`, { method: "DELETE" });
   227→    if (!res.ok) {
   228→      alert("Failed to delete template. Please try again.");
   229→      return;
   230→    }
   231→    setTemplates((prev) => prev.filter((t) => t.id !== id));
   232→  }
   233→
   234→  async function handleToggleActive(t: Template) {
   235→    const res = await fetch(`/api/admin/templates/${t.id}`, {
   236→      method: "PATCH",
   237→      headers: { "Content-Type": "application/json" },
   238→      body: JSON.stringify({ isActive: !t.isActive }),
   239→    });
   240→    if (!res.ok) {
   241→      alert("Failed to update template. Please try again.");
   242→      return;
   243→    }
   244→    router.refresh();
   245→  }
   246→
   247→  return (
   248→    <div className="space-y-4">
   249→      {templates.map((t) => {
   250→        const parsedPrompts = parsePrompts(t.prompts);
   251→        return (
   252→          <div key={t.id} className={`border rounded-2xl p-4 ${t.isActive ? "border-gray-200 bg-white" : "border-gray-100 bg-gray-50 opacity-60"}`}>
   253→            {editingId === t.id ? (
   254→              <TemplateForm
   255→                initial={t}
   256→                existingOrders={existingOrders.filter((o) => o !== t.orderNum)}
   257→                onSave={(data) => handleUpdate(t.id, data)}
   258→                onCancel={() => setEditingId(null)}
   259→              />
   260→            ) : (
   261→              <div>
   262→                <div className="flex items-start justify-between gap-3">
   263→                  <div>
   264→                    <div className="flex items-center gap-2">
   265→                      <span className="text-xs font-medium text-[#9CA3AF]">{t.yearKey} · #{t.orderNum}</span>
   266→                      {!t.isActive && <span className="text-[10px] px-2 py-0.5 bg-gray-200 text-gray-500 rounded-full">Inactive</span>}
   267→                    </div>
   268→                    <h3 className="font-semibold text-[#1A1A2E] mt-0.5">{t.title}</h3>
   269→                    {t.description && <p className="text-sm text-[#6B7280] mt-0.5">{t.description}</p>}
   270→                    <p className="text-xs text-[#9CA3AF] mt-1">
   271→                      {parsedPrompts.length} prompt{parsedPrompts.length !== 1 ? "s" : ""} · {t._count.sessions} session{t._count.sessions !== 1 ? "s" : ""} started
   272→                    </p>
   273→                  </div>
   274→                  <div className="flex items-center gap-2 flex-shrink-0">
   275→                    <button onClick={() => handleToggleActive(t)} className="text-xs text-[#6B7280] hover:text-[#1A1A2E]">
   276→                      {t.isActive ? "Deactivate" : "Activate"}
   277→                    </button>
   278→                    <button onClick={() => setEditingId(t.id)} className="text-xs text-[#3B82F6] hover:underline">
   279→                      Edit
   280→                    </button>
   281→                    <button onClick={() => handleDelete(t.id)} className="text-xs text-red-400 hover:text-red-600">
   282→                      Delete
   283→                    </button>
   284→                  </div>
   285→                </div>
   286→                <div className="mt-3 space-y-1.5">
   287→                  {parsedPrompts.map((p, i) => (
   288→                    <div key={i} className="flex items-start gap-2">
   289→                      <span className="text-[10px] px-1.5 py-0.5 bg-blue-50 text-blue-600 rounded font-medium flex-shrink-0 mt-0.5">{p.promptType}</span>
   290→                      <p className="text-sm text-[#374151]">{p.promptText}</p>
   291→                    </div>
   292→                  ))}
   293→                </div>
   294→              </div>
   295→            )}
   296→          </div>
   297→        );
   298→      })}
   299→
   300→      {creating ? (
   301→        <TemplateForm
   302→          existingOrders={existingOrders}
   303→          onSave={handleCreate}
   304→          onCancel={() => setCreating(false)}
   305→        />
   306→      ) : (
   307→        <button
   308→          onClick={() => setCreating(true)}
   309→          className="w-full py-3 border-2 border-dashed border-gray-200 rounded-2xl text-sm text-[#6B7280] hover:border-blue-300 hover:text-[#3B82F6] transition-colors"
   310→        >
   311→          + New Template
   312→        </button>
   313→      )}
   314→    </div>
   315→  );
   316→}
